```plantuml
@startuml
skinparam packageStyle folder
skinparam rectangle {
    BackgroundColor #EEEEEE
    BorderColor black
}

package "Task" <<AGGREGATE>> {
    rectangle "Task" <<AGGREGATE ROOT>> <<ENTITY>> as TaskEntity
}

package "UserStory" <<AGGREGATE>> {
    rectangle "UserStory" <<AGGREGATE ROOT>> <<ENTITY>> as UserStoryEntity
}

package "Sprint" <<AGGREGATE>> {
    rectangle "Sprint" <<AGGREGATE ROOT>> <<ENTITY>> as SprintEntity
}

package "Typology" <<AGGREGATE>> {
    rectangle "Typology" <<AGGREGATE ROOT>> <<ENTITY>> as TypologyEntity
}

package "Project" <<AGGREGATE>> {
    rectangle "Project" <<AGGREGATE ROOT>> <<ENTITY>> as ProjectEntity
    rectangle "Resource" <<AGGREGATE ROOT>> <<ENTITY>> as ProjectResourceEntity
}

package "ProfileRequest" <<AGGREGATE>> {
    rectangle "ProfileRequest" <<AGGREGATE ROOT>> <<ENTITY>> as ProfileRequestEntity
}

package "Profile" <<AGGREGATE>> {
    rectangle "Profile" <<AGGREGATE ROOT>> <<ENTITY>> as ProfileEntity
}

package "Resource" <<AGGREGATE>> {
    rectangle "Resource" <<AGGREGATE ROOT>> <<ENTITY>> as ResourceEntity
}

package "User" <<AGGREGATE>> {
    rectangle "User" <<AGGREGATE ROOT>> <<ENTITY>> as UserEntity
}

Task --> Sprint
Task --> UserStory
Task --> Project
UserStory --> Sprint
UserStory --> Project
Sprint --> Project
ProfileRequest --> Typology
ProfileRequest --> Profile
ProfileRequest --> User
Profile --> User
Resource --> Project
Resource --> User

@enduml
```
